import { createPiece } from '@activepieces/pieces-framework';
import { createCustomApiCallAction } from '@activepieces/pieces-common';
import { PieceCategory } from '@activepieces/shared';

import { alvysVoiceAuth } from './lib/auth';
import { readApiKey, regionBaseUrl } from './lib/common/client';
import { textToSpeech } from './lib/actions/text-to-speech';
import { outboundCall } from './lib/actions/calls/outbound-call';
import { getConversation } from './lib/actions/conversations/get-conversation';
import { postCallTrigger } from './lib/triggers/post-call';
import { toolCallTrigger } from './lib/triggers/tool-call';

const customApiCallDescription = `
Use this action for any voice endpoint not yet wrapped by a first-class Alvys
Voice action. Provide the path (and optional query/body) — authentication and
the residency-appropriate base URL are filled in automatically from your
connection.
`;

export const alvysVoice = createPiece({
  displayName: 'Alvys Voice',
  description:
    'Alvys-branded voice runtime — text-to-speech, outbound calls, post-call webhooks, and synchronous tool callbacks for intent-driven routing. Agents and phone numbers are provisioned by your administrator and referenced via the defaults on this connection.',
  auth: alvysVoiceAuth,
  minimumSupportedRelease: '0.36.1',
  logoUrl:
    'data:image/png;base64,',
  authors: ['alvys'],
  categories: [PieceCategory.ARTIFICIAL_INTELLIGENCE, PieceCategory.COMMUNICATION],
  actions: [
    textToSpeech,
    outboundCall,
    getConversation,
    createCustomApiCallAction({
      description: customApiCallDescription,
      auth: alvysVoiceAuth,
      baseUrl: (auth) => {
        const props = (auth as { props?: { region?: 'default' | 'us' | 'eu' } } | undefined)?.props;
        return regionBaseUrl(props?.region);
      },
      authMapping: async (auth) => ({
        'xi-api-key': `${readApiKey(auth as never)}`,
      }),
    }),
  ],
  triggers: [postCallTrigger, toolCallTrigger],
});
